import React, { useState, useEffect } from 'react';
import api from '../lib/api';

const Backups = () => {
  const [backups, setBackups] = useState([]);
  const [loading, setLoading] = useState(true);
  const [devices, setDevices] = useState([]);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      const [backupsRes, devicesRes] = await Promise.all([
        api.get('/backups/').catch(() => ({ data: [] })),
        api.get('/devices/').catch(() => ({ data: [] }))
      ]);
      setBackups(backupsRes.data.results || backupsRes.data || []);
      setDevices(devicesRes.data.results || devicesRes.data || []);
    } catch (error) {
      console.error('Error loading data:', error);
    } finally {
      setLoading(false);
    }
  };

  const createBackup = async (deviceId) => {
    try {
      await api.post('/backups/', { device: deviceId, action: 'create' });
      loadData();
    } catch (error) {
      console.error('Error creating backup:', error);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-xl font-semibold text-white">Gerenciamento de Backups</h2>
          <p className="text-gray-400 text-sm">{backups.length} backups realizados</p>
        </div>
        <button
          onClick={() => devices.length > 0 && createBackup(devices[0].id)}
          className="px-4 py-2 bg-green-600 hover:bg-green-500 text-white rounded-lg transition"
        >
          🔄 Backup de Todos
        </button>
      </div>

      {backups.length === 0 ? (
        <div className="bg-gray-800 rounded-lg p-12 text-center">
          <span className="text-6xl mb-4 block">💾</span>
          <h3 className="text-xl font-medium text-white mb-2">Nenhum backup encontrado</h3>
          <p className="text-gray-400">Os backups aparecerão aqui após serem realizados</p>
        </div>
      ) : (
        <div className="bg-gray-800 rounded-lg border border-gray-700 overflow-hidden">
          <table className="w-full">
            <thead className="bg-gray-700">
              <tr>
                <th className="px-4 py-3 text-left text-sm font-medium text-gray-300">Dispositivo</th>
                <th className="px-4 py-3 text-left text-sm font-medium text-gray-300">Tipo</th>
                <th className="px-4 py-3 text-left text-sm font-medium text-gray-300">Tamanho</th>
                <th className="px-4 py-3 text-left text-sm font-medium text-gray-300">Data</th>
                <th className="px-4 py-3 text-left text-sm font-medium text-gray-300">Status</th>
                <th className="px-4 py-3 text-right text-sm font-medium text-gray-300">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-700">
              {backups.map((backup, index) => (
                <tr key={backup.id || index} className="hover:bg-gray-700/50">
                  <td className="px-4 py-3 text-white">{backup.device_name || backup.device || '-'}</td>
                  <td className="px-4 py-3 text-gray-300">{backup.backup_type || 'Config'}</td>
                  <td className="px-4 py-3 text-gray-300">{backup.size || '-'}</td>
                  <td className="px-4 py-3 text-gray-400 text-sm">{backup.created_at || backup.timestamp || '-'}</td>
                  <td className="px-4 py-3">
                    <span className={`px-2 py-1 rounded text-xs ${
                      backup.status === 'success' ? 'bg-green-600/20 text-green-400' :
                      backup.status === 'running' ? 'bg-yellow-600/20 text-yellow-400' :
                      'bg-red-600/20 text-red-400'
                    }`}>
                      {backup.status === 'success' ? 'Sucesso' : backup.status === 'running' ? 'Executando' : 'Falhou'}
                    </span>
                  </td>
                  <td className="px-4 py-3 text-right">
                    <button className="text-blue-400 hover:text-blue-300 mr-3 text-sm">Restaurar</button>
                    <button className="text-gray-400 hover:text-gray-300 mr-3 text-sm">Download</button>
                    <button className="text-red-400 hover:text-red-300 text-sm">Excluir</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default Backups;
